// ---- Derived helpers for dashboards ----
export const myAverage = myGrades.length === 0 ? 0 : Math.round((myGrades.reduce((sum, g) => sum + g.nilai, 0) / myGrades.length) * 10) / 10;

export const totalStudents = students.length;
export const pendingConsults = consultations.filter((c) => c.status === 'Menunggu').length;

// Latest attendance day, used for the admin "today" percentage.
export const attendanceToday = (() => {
  const days = attendances.map((a) => a.waktu.slice(0, 10)).sort();
  const latest = days[days.length - 1];
  const present = attendances.filter((a) => a.waktu.startsWith(latest));
  const pct = Math.round((present.length / totalStudents) * 100);
  return { latest, present, pct };
})();
